```ts
import fs from "node:fs";
import path from "node:path";
import { PNG } from "pngjs";
import pixelmatch from "pixelmatch";
import type { Page } from "@playwright/test";
import type { VisualConfig } from "./site-types.ts";

export interface CompareOptions {
  threshold: number;
  diffImagePath: string;
}

export interface CompareResult {
  diffPixels: number;
  diffRatio: number;
  diffImagePath: string;
}

export async function captureMasked(
  page: Page,
  config: VisualConfig,
  outputPath: string
): Promise<Buffer> {
  await page.setViewportSize(config.viewport);
  const mask = config.maskSelectors.map((s) => page.locator(s));
  const buffer = await page.screenshot({ fullPage: true, mask });
  fs.mkdirSync(path.dirname(outputPath), { recursive: true });
  fs.writeFileSync(outputPath, buffer);
  return buffer;
}

export async function compareImages(
  baselinePath: string,
  currentPath: string,
  options: CompareOptions
): Promise<CompareResult> {
  const baseline = PNG.sync.read(fs.readFileSync(baselinePath));
  const current = PNG.sync.read(fs.readFileSync(currentPath));

  const width = Math.max(baseline.width, current.width);
  const height = Math.max(baseline.height, current.height);

  const a = pad(baseline, width, height);
  const b = pad(current, width, height);
  const diff = new PNG({ width, height });

  const diffPixels = pixelmatch(a.data, b.data, diff.data, width, height, {
    threshold: options.threshold,
    includeAA: false,
  });

  fs.mkdirSync(path.dirname(options.diffImagePath), { recursive: true });
  fs.writeFileSync(options.diffImagePath, PNG.sync.write(diff));

  return {
    diffPixels,
    diffRatio: diffPixels / (width * height),
    diffImagePath: options.diffImagePath,
  };
}

function pad(src: PNG, width: number, height: number): PNG {
  if (src.width === width && src.height === height) return src;
  const out = new PNG({ width, height });
  PNG.bitblt(src, out, 0, 0, src.width, src.height, 0, 0);
  return out;
}
```

