import type { PageDiff } from "@/lib/site-types";
import { VisualDiffViewer } from "./VisualDiffViewer";

export function PageDiffCard({
  diff, baselineSrc, currentSrc,
}: {
  diff: PageDiff;
  baselineSrc?: string;
  currentSrc?: string;
}) {
  const color =
    diff.severity === "critical" ? "border-red-500" :
    diff.severity === "warning" ? "border-amber-500" : "border-emerald-500";
  return (
    <article className={`rounded border-l-4 ${color} bg-card p-4`}>
      <header className="flex items-center justify-between mb-2">
        <div>
          <div className="font-mono text-sm">{diff.url}</div>
          <div className="text-xs text-muted-foreground">
            status={diff.status} · severity={diff.severity}
          </div>
        </div>
        {diff.visualDiff && (
          <div className="text-xs">
            diffRatio: {(diff.visualDiff.diffRatio * 100).toFixed(2)}%
          </div>
        )}
      </header>
      {diff.status !== "identical" && diff.status !== "missing" && baselineSrc && currentSrc && diff.visualDiff && (
        <VisualDiffViewer
          baselineSrc={baselineSrc}
          currentSrc={currentSrc}
          diffSrc={diff.visualDiff.diffImagePath}
        />
      )}
    </article>
  );
}
