```tsx
"use client";
import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { PageDiffCard } from "@/components/site/PageDiffCard";
import type { SiteReport, SiteRunResult } from "@/lib/site-types";
import path from "path-browserify";

export default function ReportPage() {
  const params = useParams<{ id: string; runId: string }>();
  const [report, setReport] = useState<SiteReport | null>(null);
  const [current, setCurrent] = useState<SiteRunResult | null>(null);

  useEffect(() => {
    void (async () => {
      const [r1, r2] = await Promise.all([
        fetch(`/api/sites/${params.id}/runs/${params.runId}/report`).then((r) => r.json()),
        fetch(`/api/sites/${params.id}/runs/${params.runId}`).then((r) => r.json()),
      ]);
      if (r1.success) setReport(r1.data);
      if (r2.success) setCurrent(r2.data);
    })();
  }, [params.id, params.runId]);

  if (!report) return <main className="px-4 py-8">불러오는 중...</main>;

  const fileByUrl = new Map(
    (current?.pages ?? []).map((p) => [
      p.url,
      p.screenshotPath ? path.basename(p.screenshotPath) : undefined,
    ])
  );

  return (
    <main className="px-4 py-8 grid gap-3">
      <header className="mb-4">
        <h1 className="text-2xl font-bold">회귀 리포트</h1>
        <div className="text-sm text-muted-foreground">
          overall: {report.overall} · baseline {report.baselineRunId} → current {report.currentRunId}
        </div>
      </header>
      {report.pageDiffs.map((d) => {
        const file = fileByUrl.get(d.url);
        return (
          <PageDiffCard
            key={d.url}
            diff={d}
            baselineSrc={file ? `/api/sites/${params.id}/baseline/screenshot/${file}` : undefined}
            currentSrc={file ? `/api/sites/${params.id}/runs/${params.runId}/screenshot/${file}` : undefined}
          />
        );
      })}
    </main>
  );
}
```

