import type { SiteRunProgress } from "./site-types.ts";

const progressMap = new Map<string, SiteRunProgress>();

export function setSiteRunProgress(p: SiteRunProgress): void {
  progressMap.set(p.siteId, p);
}

export function getSiteRunProgress(siteId: string): SiteRunProgress | null {
  return progressMap.get(siteId) ?? null;
}

export function updateSiteRunProgress(
  siteId: string,
  patch: (p: SiteRunProgress) => SiteRunProgress
): void {
  const existing = progressMap.get(siteId);
  if (existing) progressMap.set(siteId, patch(existing));
}

export function clearSiteRunProgress(siteId: string): void {
  progressMap.delete(siteId);
}
