import type {
  PageDiff, PageDiffStatus, Site, SitePageCapture, SiteReport, SiteRunResult,
} from "./site-types.ts";

export type VisualDiffFn = (
  baselineCapture: SitePageCapture,
  currentCapture: SitePageCapture,
  diffImagePath: string
) => Promise<{ diffPixels: number; diffRatio: number; diffImagePath: string }>;

export async function diffSiteRuns(
  site: Site,
  baseline: SiteRunResult,
  current: SiteRunResult,
  visualDiff: VisualDiffFn
): Promise<SiteReport> {
  const byUrlBase = new Map(baseline.pages.map((p) => [p.url, p]));
  const byUrlCurr = new Map(current.pages.map((p) => [p.url, p]));
  const allUrls = new Set<string>([...byUrlBase.keys(), ...byUrlCurr.keys()]);

  const pageDiffs: PageDiff[] = [];

  for (const url of allUrls) {
    const b = byUrlBase.get(url);
    const c = byUrlCurr.get(url);

    if (b && !c) { pageDiffs.push({ url, status: "missing", severity: "critical" }); continue; }
    if (!b && c) { pageDiffs.push({ url, status: "added", severity: "info" }); continue; }
    if (!b || !c) continue;

    const domChanged = site.dom.enabled && b.domHash !== c.domHash;
    let visualChanged = false;
    let visualResult: PageDiff["visualDiff"];

    if (site.visual.enabled && b.screenshotPath && c.screenshotPath) {
      const diff = await visualDiff(b, c, `${current.runId}-${encodeURIComponent(url)}.diff.png`);
      visualResult = diff;
      visualChanged = diff.diffRatio > site.visual.maxDiffRatio;
    }

    const status: PageDiffStatus =
      domChanged && visualChanged ? "both" :
      domChanged ? "domChanged" :
      visualChanged ? "visualChanged" : "identical";

    const severity: PageDiff["severity"] =
      status === "both" ? "critical" :
      status === "identical" ? "info" : "warning";

    pageDiffs.push({ url, status, severity, visualDiff: visualResult });
  }

  const hasError = current.errors.length > 0 || baseline.errors.length > 0;
  const hasDifference = pageDiffs.some((d) => d.status !== "identical");
  const overall: SiteReport["overall"] = hasError ? "error" : hasDifference ? "different" : "identical";

  return {
    siteId: site.id,
    baselineRunId: baseline.runId,
    currentRunId: current.runId,
