```ts
import fs from "node:fs";
import path from "node:path";
import type { SiteRunResult } from "./site-types.ts";

function siteDir(siteId: string): string {
  return path.join(process.cwd(), "data", "sites", siteId);
}

export function loadBaseline(siteId: string): SiteRunResult | null {
  const target = path.join(siteDir(siteId), "baseline.json");
  if (!fs.existsSync(target)) return null;
  return JSON.parse(fs.readFileSync(target, "utf-8")) as SiteRunResult;
}

export function promoteRunToBaseline(siteId: string, runId: string): void {
  const dir = siteDir(siteId);
  const runJson = path.join(dir, "runs", `${runId}.json`);
  const runShots = path.join(dir, "runs", runId);
  if (!fs.existsSync(runJson)) throw new Error(`Run not found: ${runId}`);

  const baselineJson = path.join(dir, "baseline.json");
  const baselineShots = path.join(dir, "baseline");

  if (fs.existsSync(baselineJson)) {
    const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
    fs.renameSync(baselineJson, path.join(dir, `baseline.${ts}.archive.json`));
  }
  if (fs.existsSync(baselineShots)) {
    fs.rmSync(baselineShots, { recursive: true, force: true });
  }

  fs.copyFileSync(runJson, baselineJson);
  if (fs.existsSync(runShots)) {
    fs.mkdirSync(baselineShots, { recursive: true });
    for (const entry of fs.readdirSync(runShots)) {
      fs.copyFileSync(path.join(runShots, entry), path.join(baselineShots, entry));
    }
  }
}
```

