import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { listSites, saveSite } from "@/lib/site-manager";
import { isHttpUrl } from "@/lib/url-normalizer";
import type { Site } from "@/lib/site-types";

export async function GET() {
  return NextResponse.json({ success: true, data: listSites() });
}

export async function POST(req: NextRequest) {
  try {
    const body = (await req.json()) as Site;
    validate(body);
    const now = new Date().toISOString();
    saveSite({ ...body, createdAt: now, updatedAt: now });
    return NextResponse.json({ success: true, data: body });
  } catch (error) {
    return NextResponse.json(
      { success: false, error: error instanceof Error ? error.message : String(error) },
      { status: 400 }
    );
  }
}

function validate(site: Site) {
  if (!site.id || !/^[\w-]+$/.test(site.id)) throw new Error("Invalid id");
  if (!site.name?.trim()) throw new Error("name required");
  if (!Array.isArray(site.crawl?.startUrls) || site.crawl.startUrls.length === 0) {
    throw new Error("startUrls required");
  }
  for (const u of site.crawl.startUrls) {
    if (!isHttpUrl(u)) throw new Error(`startUrl not http(s): ${u}`);
  }
  for (const pat of [...(site.crawl.includePatterns ?? []), ...(site.crawl.excludePatterns ?? [])]) {
    try { new RegExp(pat); } catch { throw new Error(`Bad regex: ${pat}`); }
  }
}
