**Step 3: Implement**

```ts
import { isHttpUrl, normalizeUrl, sameOrigin } from "./url-normalizer.ts";
import type { SiteCrawlConfig } from "./site-types.ts";

export interface CrawlPage {
  goto(url: string): Promise<{ status: () => number; url: () => string } | null>;
  getLinks(): Promise<string[]>;
  url(): string;
}

export interface VisitRecord {
  url: string; finalUrl: string; httpStatus: number; depth: number;
}

export interface SkipRecord {
  url: string;
  reason: "depth" | "pattern" | "external" | "limit" | "duplicate" | "non-http";
}

export interface CrawlOutcome {
  visited: VisitRecord[];
  skipped: SkipRecord[];
  errors: { url: string; message: string }[];
}

export async function crawl(
  page: CrawlPage,
  config: SiteCrawlConfig,
  onVisit?: (record: VisitRecord) => Promise<void>
): Promise<CrawlOutcome> {
  const visited = new Set<string>();
  const visitedRecords: VisitRecord[] = [];
  const skipped: SkipRecord[] = [];
  const errors: { url: string; message: string }[] = [];

  const queue: { url: string; depth: number }[] = [];
  const origins: string[] = [];

  for (const raw of config.startUrls) {
    const n = normalizeUrl(raw);
    if (n) {
      queue.push({ url: n, depth: 0 });
      origins.push(n);
    }
  }

  const includeREs = (config.includePatterns ?? []).map((p) => new RegExp(p));
  const excludeREs = (config.excludePatterns ?? []).map((p) => new RegExp(p));

  while (queue.length > 0) {
    if (visited.size >= config.maxPages) {
      for (const q of queue) skipped.push({ url: q.url, reason: "limit" });
      break;
    }

    const next = queue.shift();
    if (!next) break;

    if (visited.has(next.url)) { skipped.push({ url: next.url, reason: "duplicate" }); continue; }
    if (next.depth > config.maxDepth) { skipped.push({ url: next.url, reason: "depth" }); continue; }
    if (!isHttpUrl(next.url)) { skipped.push({ url: next.url, reason: "non-http" }); continue; }

    const internal = origins.some((o) => sameOrigin(o, next.url, config.allowSubdomains));
    if (!internal) { skipped.push({ url: next.url, reason: "external" }); continue; }

    if (excludeREs.some((re) => re.test(next.url))) {
      skipped.push({ url: next.url, reason: "pattern" }); continue;
    }
    if (includeREs.length > 0 && !includeREs.some((re) => re.test(next.url))) {
      skipped.push({ url: next.url, reason: "pattern" }); continue;
    }

    visited.add(next.url);

    try {
      const response = await page.goto(next.url);
      const finalUrl = response?.url() ?? next.url;
      const status = response?.status() ?? 0;
      const record: VisitRecord = { url: next.url, finalUrl, httpStatus: status, depth: next.depth };
      visitedRecords.push(record);
      if (onVisit) await onVisit(record);

      if (next.depth < config.maxDepth) {
        for (const raw of await page.getLinks()) {
          if (
            !isHttpUrl(raw) &&
            !raw.startsWith("/") &&
            !raw.startsWith("./") &&
            !raw.startsWith("../")
          ) {
            skipped.push({ url: raw, reason: "non-http" });
            continue;
          }
          const normalized = normalizeUrl(raw, finalUrl);
          if (!normalized) continue;
          if (!visited.has(normalized)) queue.push({ url: normalized, depth: next.depth + 1 });
        }
      }
    } catch (error) {
      errors.push({ url: next.url, message: error instanceof Error ? error.message : String(error) });
    }
  }

  return { visited: visitedRecords, skipped, errors };
}
```

