```ts
import fs from "node:fs";
import path from "node:path";
import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { loadBaseline } from "@/lib/site-baseline";
import { compareImages } from "@/lib/visual-diff";
import { getSite } from "@/lib/site-manager";
import { runSite } from "@/lib/site-runner";
import { diffSiteRuns, type VisualDiffFn } from "@/lib/site-diff-engine";

export async function POST(_: NextRequest, { params }: { params: { id: string } }) {
  try {
    const site = getSite(params.id);
    if (!site) return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });

    const baseline = loadBaseline(params.id);
    if (!baseline) {
      return NextResponse.json(
        { success: false, error: "베이스라인을 먼저 채택하세요" },
        { status: 400 }
      );
    }

    const current = await runSite(site);

    const visualDiff: VisualDiffFn = async (b, c, diffName) => {
      if (!b.screenshotPath || !c.screenshotPath) {
        return { diffPixels: 0, diffRatio: 0, diffImagePath: "" };
      }
      const diffDir = path.join("data", "sites", site.id, "runs", current.runId, "diff");
      fs.mkdirSync(diffDir, { recursive: true });
      const diffPath = path.join(diffDir, diffName);
      return compareImages(b.screenshotPath, c.screenshotPath, {
        threshold: site.visual.threshold,
        diffImagePath: diffPath,
      });
    };

    const report = await diffSiteRuns(site, baseline, current, visualDiff);

    const runDir = path.join("data", "sites", site.id, "runs", current.runId);
    fs.mkdirSync(runDir, { recursive: true });
    fs.writeFileSync(path.join(runDir, "report.json"), JSON.stringify(report, null, 2), "utf-8");

    return NextResponse.json({ success: true, data: { report, current } });
  } catch (error) {
    return NextResponse.json(
      { success: false, error: error instanceof Error ? error.message : String(error) },
      { status: 500 }
    );
  }
}
```

