import fs from "node:fs";
import path from "node:path";
import { NextResponse } from "next/server";

export async function GET(_: Request, { params }: { params: { id: string; runId: string } }) {
  if (!/^[\w-]+$/.test(params.id) || !/^[\w-]+$/.test(params.runId)) {
    return NextResponse.json({ success: false, error: "Bad id" }, { status: 400 });
  }
  const reportFile = path.join(
    process.cwd(), "data", "sites", params.id, "runs", params.runId, "report.json"
  );
  if (!fs.existsSync(reportFile)) {
    return NextResponse.json({ success: false, error: "Report not found — run /compare first" }, { status: 404 });
  }
  return NextResponse.json({
    success: true,
    data: JSON.parse(fs.readFileSync(reportFile, "utf-8")),
  });
}
