"use client";
import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { Button } from "@/components/ui/button";
import type { SiteRunProgress, SiteRunResult } from "@/lib/site-types";

export default function RunPage() {
  const params = useParams<{ id: string }>();
  const [result, setResult] = useState<SiteRunResult | null>(null);
  const [progress, setProgress] = useState<SiteRunProgress | null>(null);
  const [running, setRunning] = useState(false);

  useEffect(() => {
    if (!running) return;
    const handle = setInterval(async () => {
      const res = await fetch(`/api/sites/${params.id}/run-status`);
      const payload = await res.json();
      setProgress(payload.data);
      if (payload.data?.status === "completed" || payload.data?.status === "error") {
        setRunning(false);
        clearInterval(handle);
      }
    }, 1000);
    return () => clearInterval(handle);
  }, [running, params.id]);

  async function handleRun() {
    setRunning(true);
    setResult(null);
    const res = await fetch(`/api/sites/${params.id}/run`, { method: "POST" });
    const payload = await res.json();
    if (payload.success) setResult(payload.data);
    setRunning(false);
  }

  async function handleAdoptBaseline() {
    if (!result) return;
    if (!window.confirm("이 실행을 베이스라인으로 채택하시겠습니까?")) return;
    const res = await fetch(`/api/sites/${params.id}/baseline`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ runId: result.runId }),
    });
    const payload = await res.json();
    alert(payload.success ? "베이스라인 채택 완료" : `실패: ${payload.error}`);
  }

  async function handleCompare() {
    const res = await fetch(`/api/sites/${params.id}/compare`, { method: "POST" });
    const payload = await res.json();
    if (!payload.success) return alert(payload.error);
    window.location.href = `/sites/${params.id}/report/${payload.data.current.runId}`;
  }

  return (
    <main className="px-4 py-8">
      <h1 className="mb-4 text-2xl font-bold">사이트 실행</h1>
      <div className="flex gap-3 mb-6">
        <Button onClick={handleRun} disabled={running}>
          {running ? "실행 중..." : "실행"}
        </Button>
        <Button variant="secondary" onClick={handleAdoptBaseline} disabled={!result}>
          베이스라인으로 채택
        </Button>
        <Button variant="secondary" onClick={handleCompare}>
          베이스라인과 비교
        </Button>
      </div>

      {progress && (
        <div className="mb-6 rounded border p-3 text-sm">
          상태: {progress.status} · 방문: {progress.visited}/{progress.total}
          {progress.currentUrl && <div className="text-muted-foreground">{progress.currentUrl}</div>}
          {progress.error && <div className="text-red-600">{progress.error}</div>}
        </div>
      )}

      {result && (
        <div className="rounded border p-3">
          <div>RunId: {result.runId}</div>
          <div>방문 페이지: {result.pages.length}</div>
          <div>에러: {result.errors.length}</div>
        </div>
      )}
    </main>
  );
}
