    process.cwd(), "data", "sites", params.id, "runs", params.runId, params.fileName
  );
  if (!fs.existsSync(target)) return new NextResponse("Not found", { status: 404 });
  const buf = fs.readFileSync(target);
  return new NextResponse(buf, {
    status: 200,
    headers: { "Content-Type": "image/png", "Cache-Control": "no-store" },
  });
}
