export function SiteForm({
  initial, onSave, storageStateUploader,
}: {
  initial: Site;
  onSave: (site: Site) => Promise<void>;
  storageStateUploader?: (json: object) => Promise<void>;
}) {
  const [site, setSite] = useState<Site>(initial);

  function setCrawl<K extends keyof Site["crawl"]>(key: K, value: Site["crawl"][K]) {
    setSite((s) => ({ ...s, crawl: { ...s.crawl, [key]: value } }));
  }

  return (
    <form
      className="grid gap-4 max-w-2xl"
      onSubmit={async (e) => { e.preventDefault(); await onSave(site); }}
    >
      <label className="grid gap-1">
        <span>ID</span>
        <input className="rounded border px-2 py-1"
          value={site.id}
          onChange={(e) => setSite((s) => ({ ...s, id: e.target.value }))}
          required />
      </label>

      <label className="grid gap-1">
        <span>이름</span>
        <input className="rounded border px-2 py-1"
          value={site.name}
          onChange={(e) => setSite((s) => ({ ...s, name: e.target.value }))}
          required />
      </label>

      <label className="grid gap-1">
        <span>Start URLs (한 줄에 하나)</span>
        <textarea className="rounded border px-2 py-1 font-mono text-sm" rows={3}
          value={site.crawl.startUrls.join("\n")}
          onChange={(e) => setCrawl("startUrls",
            e.target.value.split("\n").map((s) => s.trim()).filter(Boolean))} />
      </label>

      <div className="grid grid-cols-3 gap-3">
        <label className="grid gap-1">
          <span>maxDepth</span>
          <input type="number" min={0} className="rounded border px-2 py-1"
            value={site.crawl.maxDepth}
            onChange={(e) => setCrawl("maxDepth", Number(e.target.value))} />
        </label>
        <label className="grid gap-1">
          <span>maxPages</span>
          <input type="number" min={1} className="rounded border px-2 py-1"
            value={site.crawl.maxPages}
            onChange={(e) => setCrawl("maxPages", Number(e.target.value))} />
        </label>
        <label className="grid gap-1 items-end">
          <span>서브도메인 허용</span>
          <input type="checkbox"
            checked={site.crawl.allowSubdomains}
            onChange={(e) => setCrawl("allowSubdomains", e.target.checked)} />
        </label>
      </div>

      <label className="grid gap-1">
        <span>excludePatterns (정규식, 한 줄에 하나)</span>
        <textarea className="rounded border px-2 py-1 font-mono text-sm" rows={2}
          value={(site.crawl.excludePatterns ?? []).join("\n")}
          onChange={(e) => setCrawl("excludePatterns",
            e.target.value.split("\n").map((s) => s.trim()).filter(Boolean))} />
      </label>

      <label className="grid gap-1">
        <span>maskSelectors (CSS, 한 줄에 하나)</span>
        <textarea className="rounded border px-2 py-1 font-mono text-sm" rows={2}
          value={site.visual.maskSelectors.join("\n")}
          onChange={(e) => setSite((s) => ({
            ...s, visual: {
