import fs from "node:fs";
import path from "node:path";
import { NextResponse } from "next/server";

export async function GET(_: Request, { params }: { params: { id: string } }) {
  if (!/^[\w-]+$/.test(params.id)) {
    return NextResponse.json({ success: false, error: "Bad id" }, { status: 400 });
  }
  const dir = path.join(process.cwd(), "data", "sites", params.id, "runs");
  if (!fs.existsSync(dir)) return NextResponse.json({ success: true, data: [] });
  const entries = fs.readdirSync(dir).filter((e) => e.endsWith(".json")).sort().reverse();
  return NextResponse.json({ success: true, data: entries.map((e) => e.replace(/\.json$/, "")) });
}
