```ts
import { createHash } from "node:crypto";
import { JSDOM } from "jsdom";
import type { DomConfig } from "./site-types.ts";

const ID_LIKE_ATTR_PATTERN = /-?[a-z0-9]{6,}/gi;
const ID_BEARING_ATTRS = new Set([
  "aria-describedby",
  "aria-labelledby",
  "aria-controls",
  "aria-owns",
  "id",
  "for",
]);

export interface NormalizeResult {
  serialized: string;
  hash: string;
}

export function normalizeHtmlString(html: string, config: DomConfig): NormalizeResult {
  const dom = new JSDOM(html);
  const document = dom.window.document;

  document.querySelectorAll("script, style, noscript").forEach((n) => n.remove());
  for (const selector of config.ignoreSelectors) {
    document.querySelectorAll(selector).forEach((n) => n.remove());
  }

  walk(document.body, config);

  const serialized = document.body ? document.body.outerHTML : "";
  const hash = createHash("sha256").update(serialized).digest("hex");

  return { serialized, hash };
}

function walk(node: Element | null, config: DomConfig): void {
  if (!node) return;

  if (node.attributes) {
    const attrs = Array.from(node.attributes);
    const sorted = attrs
      .map((a) => ({
        name: a.name,
        value: ID_BEARING_ATTRS.has(a.name)
          ? a.value.replace(ID_LIKE_ATTR_PATTERN, "<id>")
          : a.value,
      }))
      .sort((x, y) => x.name.localeCompare(y.name));

    for (const a of attrs) node.removeAttribute(a.name);
    for (const { name, value } of sorted) node.setAttribute(name, value);
  }

  for (const child of Array.from(node.childNodes)) {
    if (child.nodeType === 3) {
      if (config.normalizeWhitespace && child.textContent) {
        child.textContent = child.textContent.replace(/\s+/g, " ").trim();
      }
    } else if (child.nodeType === 1) {
      walk(child as Element, config);
    }
  }
}
```

