import fs from "node:fs";
import path from "node:path";
import type { Site } from "./site-types.ts";

const SITES_DIR = () => path.join(process.cwd(), "data", "sites");

function ensureDir() {
  const dir = SITES_DIR();
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

function assertSafeId(id: string): void {
  if (!/^[\w-]+$/.test(id)) throw new Error(`Invalid site id: ${id}`);
}

function filePath(id: string): string {
  assertSafeId(id);
  ensureDir();
  return path.join(SITES_DIR(), `${id}.json`);
}

export function listSites(): Site[] {
  ensureDir();
  return fs
    .readdirSync(SITES_DIR())
    .filter((e) => e.endsWith(".json"))
    .flatMap((e) => {
      try {
        return [JSON.parse(fs.readFileSync(path.join(SITES_DIR(), e), "utf-8")) as Site];
      } catch {
        return [];
      }
    });
}

export function getSite(id: string): Site | null {
  const target = filePath(id);
  if (!fs.existsSync(target)) return null;
  return JSON.parse(fs.readFileSync(target, "utf-8")) as Site;
}

export function saveSite(site: Site): void {
  const target = filePath(site.id);
  fs.writeFileSync(target, JSON.stringify(site, null, 2), "utf-8");
  const siteDir = path.join(SITES_DIR(), site.id);
  if (!fs.existsSync(siteDir)) fs.mkdirSync(siteDir, { recursive: true });
}

export function deleteSite(id: string): boolean {
  const target = filePath(id);
  if (!fs.existsSync(target)) return false;
  fs.unlinkSync(target);
  const siteDir = path.join(SITES_DIR(), id);
  if (fs.existsSync(siteDir)) fs.rmSync(siteDir, { recursive: true, force: true });
  return true;
}
```

